/**
 * Post-generation patch for Drizzle Kit's db/schema.ts
 *
 * Drizzle Kit generates circular foreign key references (user → file → user)
 * that TypeScript cannot infer, causing TS7022/TS7024 errors.
 * This script prepends @ts-nocheck to suppress those errors in the
 * auto-generated file while keeping strict checking for all hand-written code.
 *
 * Usage: node scripts/patch-drizzle-schema.js
 */

import { readFileSync, writeFileSync } from 'fs'
import { join, dirname } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const schemaPath = join(__dirname, '..', 'db', 'schema.ts')

const content = readFileSync(schemaPath, 'utf-8')

if (!content.startsWith('// @ts-nocheck')) {
  writeFileSync(
    schemaPath,
    `// @ts-nocheck — auto-generated by Drizzle Kit, circular FKs cause inference issues\n${content}`,
  )
  console.log('✅ Patched db/schema.ts with @ts-nocheck')
} else {
  console.log('ℹ️  db/schema.ts already patched')
}
